# Utility module with helper functions for shapes

from shapes import Shape, Rectangle

class ShapeFactory:
    @staticmethod
    def create_square(size: float) -> Rectangle:
        return Rectangle(size, size)

    @staticmethod
    def create_default_shape() -> Shape:
        return Shape("Default")

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def describe_shapes(shapes: list[Shape]) -> list[str]:
    descriptions: list[str] = []
    for s in shapes:
        descriptions.append(s.describe())
    return descriptions
